/**
 * Throttle a function to once per interval.
 * @param {(value: unknown) => void} fn
 * @param {number} waitMs
 * @returns {{ call: (value: unknown) => void, cancel: () => void }}
 */
export function throttle(fn, waitMs) {
  let timerId;
  let lastValue;

  const cancel = () => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
  };

  const call = (value) => {
    lastValue = value;
    if (timerId !== undefined) {
      return;
    }
    fn(lastValue);
    timerId = setTimeout(() => {
      timerId = undefined;
    }, waitMs);
  };

  return { call, cancel };
}
